<?php
namespace Tests\Feature\Hr;
use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Schema; use Tests\TestCase;
class HrPhase4BTrainingRollbackTest extends TestCase { use RefreshHrDatabase; public function test_training_schema_exists():void{$this->assertTrue(Schema::hasColumns('hr_training_courses',['passing_score','certificate_validity_months','is_mandatory']));$this->assertTrue(Schema::hasColumns('hr_training_sessions',['delivery_type','starts_at','capacity']));$this->assertTrue(Schema::hasColumns('hr_training_enrollments',['progress_percent','exam_score','passed']));$this->assertTrue(Schema::hasColumns('hr_certificates',['certificate_number','issued_on','expires_on','file_id']));$this->assertTrue(Schema::hasColumn('hr_shift_templates','required_training_course_id'));} public function test_rollback_preserves_performance_tables():void{Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>3]);Artisan::call('migrate:rollback',['--step'=>5]);$this->assertFalse(Schema::hasTable('hr_training_courses'));$this->assertTrue(Schema::hasTable('hr_performance_cycles'));$this->assertTrue(Schema::hasTable('hr_integration_outbox'));} }
